}

// Render the gallery
html`&lt;div class="gallery-grid"&gt;
  ${selectedImages.map(img =&gt; `
    &lt;div class="gallery-item"&gt;
      &lt;img src="figures/gecco_ecip_2025/${img}" class="gallery-img" loading="lazy"&gt;
    &lt;/div&gt;
  `).join('')}
&lt;/div&gt;`

